// WRONG: khởi động tất cả cùng lúc
await Task.WhenAll(items.Select(item => ProcessAsync(item, ct)));

// RIGHT: Parallel.ForEachAsync với throttle
await Parallel.ForEachAsync(
    items,
    new ParallelOptions { MaxDegreeOfParallelism = 8, CancellationToken = ct },
    async (item, innerCt) => await ProcessAsync(item, innerCt));

// Với IAsyncEnumerable source (streaming + parallel)
await Parallel.ForEachAsync(
    GetItemsAsync(ct),
    new ParallelOptions { MaxDegreeOfParallelism = 4, CancellationToken = ct },
    async (item, innerCt) => await SaveToDbAsync(item, innerCt));

// Khi cần kết quả: dùng ConcurrentBag
var results = new ConcurrentBag<Result>();
await Parallel.ForEachAsync(items, opts, async (item, innerCt) =>
{
    var r = await ComputeAsync(item, innerCt);
    results.Add(r);
});
